function openModal(id) {
  const p = products[id];
  if(!p) return;
  document.getElementById('modalImg').src = p.img;
  document.getElementById('modalBrand').textContent = p.brand;
  document.getElementById('modalTitle').textContent = p.title;
  document.getElementById('modalDesc').textContent = p.desc;
  const fl = document.getElementById('modalFeatures');
  fl.innerHTML = p.features.map(f=>`<li><span class="mf-check">✓</span>${f}</li>`).join('');
  document.getElementById('productModal').classList.add('open');
}
function closeModal(){ document.getElementById('productModal').classList.remove('open') }
function openWA(){ window.open('https://wa.me/918686609718?text=Hi%20RK%20Aqua%20Solutions!%20I%20am%20interested%20in%20a%20water%20purifier.%20Please%20help%20me.','_blank') }

function handleSubmit(btn){
  btn.textContent = '✅ Enquiry Sent! We\'ll call you soon.';
  btn.style.background = '#4CAF50';
  btn.style.color = '#fff';
  setTimeout(()=>{ btn.textContent='📩 Send Enquiry'; btn.style.background=''; btn.style.color=''; },4000);
}

document.getElementById('productModal').addEventListener('click', function(e){
  if(e.target === this) closeModal();
});